
namespace Qyl.Collector.Storage.Generators;

internal static class DuckDbEmitter
{
    public static string Emit(DuckDbTableInfo table)
    {
        var sb = new StringBuilder(4096);

        sb.AppendLine("""
                      // <auto-generated/>
                      // DuckDB helpers for type-safe parameter binding and reader mapping

                      #nullable enable

                      using System;
                      using System.Collections.Concurrent;
                      using System.Data.Common;
                      using System.Runtime.CompilerServices;
                      using System.Text;
                      using DuckDB.NET.Data;
                      """);

        sb.Append("namespace ").Append(table.Namespace).AppendLine(";");
        sb.AppendLine();

        sb.Append("partial ").Append(table.TypeKind).Append(' ').AppendLine(table.TypeName);
        sb.AppendLine("{");

        var insertColumns = table.Columns.Where(static c => !c.ExcludeFromInsert).ToArray();

        sb.AppendLine("    private static readonly ConcurrentDictionary<int, string> s_insertSqlCache = new();");
        sb.AppendLine();

        EmitColumnLists(sb, table.TableName, insertColumns, [.. table.Columns]);

        sb.Append("    public const int ColumnCount = ").Append(insertColumns.Length).AppendLine(";");
        sb.AppendLine();

        EmitCreateTableDdl(sb, table);

        EmitAddParameters(sb, table.TypeName, insertColumns);

        EmitMapFromReader(sb, table, [.. table.Columns]);

        EmitBuildMultiRowInsertSql(sb, table);

        sb.AppendLine("}");

        return sb.ToString();
    }

    private static void EmitColumnLists(
        StringBuilder sb,
        string tableName,
        DuckDbColumnInfo[] insertColumns,
        DuckDbColumnInfo[] selectColumns)
    {
        sb.Append("    public const string TableName = \"").Append(tableName).AppendLine("\";");
        sb.Append("    private const string QuotedTableName = \"")
            .Append(EscapeCSharpString(SqlIdentifier.Quote(tableName)))
            .AppendLine("\";");
        sb.AppendLine();

        EmitColumnListConstant(sb, "ColumnList", insertColumns);
        EmitColumnListConstant(sb, "SelectColumnList", selectColumns);
    }

    private static void EmitColumnListConstant(StringBuilder sb, string name, DuckDbColumnInfo[] columns)
    {
        sb.Append("    public const string ").Append(name).AppendLine(" = \"\"\"");
        EmitQuotedColumnList(sb, columns);
        sb.AppendLine("        \"\"\";");
        sb.AppendLine();
    }

    private static void EmitQuotedColumnList(StringBuilder sb, DuckDbColumnInfo[] columns)
    {
        sb.Append("        ");
        for (var i = 0; i < columns.Length; i++)
        {
            if (i > 0)
            {
                sb.Append(", ");
                if (i % 4 is 0)
                {
                    sb.AppendLine();
                    sb.Append("        ");
                }
            }

            sb.Append(SqlIdentifier.Quote(columns[i].ColumnName));
        }

        sb.AppendLine();
    }

    private static void EmitCreateTableDdl(StringBuilder sb, DuckDbTableInfo table)
    {
        sb.AppendLine("    public const string CreateTableDdl = \"\"\"");
        sb.Append("        CREATE TABLE IF NOT EXISTS ").Append(SqlIdentifier.Quote(table.TableName)).AppendLine(" (");

        var primaryKeyColumns = table.Columns
            .Where(static c => c.PrimaryKeyOrdinal >= 0)
            .OrderBy(static c => c.PrimaryKeyOrdinal)
            .ToArray();

        for (var i = 0; i < table.Columns.Length; i++)
        {
            var column = table.Columns[i];
            sb.Append("            ")
                .Append(SqlIdentifier.Quote(column.ColumnName))
                .Append(' ')
                .Append(ResolveSqlType(column));

            if (!column.IsNullable)
                sb.Append(" NOT NULL");

            if (!string.IsNullOrWhiteSpace(column.DefaultSql))
                sb.Append(" DEFAULT ").Append(column.DefaultSql);

            if (i < table.Columns.Length - 1 || primaryKeyColumns.Length > 0)
                sb.Append(',');

            sb.AppendLine();
        }

        if (primaryKeyColumns.Length > 0)
        {
            sb.Append("            PRIMARY KEY (");
            for (var i = 0; i < primaryKeyColumns.Length; i++)
            {
                if (i > 0)
                    sb.Append(", ");

                sb.Append(SqlIdentifier.Quote(primaryKeyColumns[i].ColumnName));
            }

            sb.AppendLine(")");
        }

        sb.AppendLine("        );");
        sb.AppendLine("        \"\"\";");
        sb.AppendLine();
    }

    private static string ResolveSqlType(DuckDbColumnInfo column)
    {
        if (!string.IsNullOrWhiteSpace(column.SqlType))
            return column.SqlType!;

        var type = column.PropertyType.TrimEnd('?');
        if (column.IsUBigInt)
            return "UBIGINT";

        return type switch
        {
            "string" or "System.String" => "VARCHAR",
            "byte" or "System.Byte" => "TINYINT",
            "int" or "System.Int32" => "INTEGER",
            "long" or "System.Int64" => "BIGINT",
            "ulong" or "System.UInt64" => "UBIGINT",
            "double" or "System.Double" => "DOUBLE",
            "decimal" or "System.Decimal" => "DECIMAL",
            "bool" or "System.Boolean" => "BOOLEAN",
            "System.DateTimeOffset" or "DateTimeOffset" => "TIMESTAMP",
            _ => throw new InvalidOperationException(
                $"No DuckDB SQL type mapping for {column.PropertyType} on {column.PropertyName}. Set SqlType explicitly.")
        };
    }

    private static string EscapeCSharpString(string value) =>
        value.Replace("\\", "\\\\").Replace("\"", "\\\"");

    private static void EmitAddParameters(StringBuilder sb, string typeName, IEnumerable<DuckDbColumnInfo> columns)
    {
        sb.AppendLine("    /// <summary>");
        sb.AppendLine("    /// Adds parameters for INSERT in column order.");
        sb.AppendLine("    /// </summary>");
        sb.AppendLine("    [MethodImpl(MethodImplOptions.AggressiveInlining)]");
        sb.Append("    public static void AddParameters(DuckDBCommand cmd, ").Append(typeName).AppendLine(" row)");
        sb.AppendLine("    {");

        foreach (var col in columns)
        {
            EmitParameterAdd(sb, col);
        }

        sb.AppendLine("    }");
        sb.AppendLine();
    }

    private static void EmitParameterAdd(StringBuilder sb, DuckDbColumnInfo col)
    {
        sb.Append("        cmd.Parameters.Add(new DuckDBParameter { Value = ");

        var valueExpr = $"row.{col.PropertyName}";

        if (col.IsUBigInt)
        {
            if (col.IsNullable)
            {
                sb.Append(valueExpr).Append(".HasValue ? (object)(decimal)").Append(valueExpr)
                    .Append(".Value : DBNull.Value");
            }
            else
            {
                sb.Append("(decimal)").Append(valueExpr);
            }
        }
        else if (col.IsNullable)
        {
            sb.Append(valueExpr).Append(" ?? (object)DBNull.Value");
        }
        else
        {
            sb.Append(valueExpr);
        }

        sb.AppendLine(" });");
    }

    private static void EmitMapFromReader(StringBuilder sb, DuckDbTableInfo table,
        IReadOnlyList<DuckDbColumnInfo> columns)
    {
        sb.AppendLine("    /// <summary>");
        sb.AppendLine("    /// Maps a DbDataReader row to the type using ordinal-based access.");
        sb.AppendLine("    /// </summary>");
        sb.AppendLine("    [MethodImpl(MethodImplOptions.AggressiveInlining)]");
        sb.Append("    public static ").Append(table.TypeName).AppendLine(" MapFromReader(DbDataReader reader)");
        sb.AppendLine("    {");
        sb.Append("        return new ").Append(table.TypeName).AppendLine();
        sb.AppendLine("        {");

        for (var i = 0; i < columns.Count; i++)
        {
            var col = columns[i];
            var ordinal = col.Ordinal;

            sb.Append("            ").Append(col.PropertyName).Append(" = ");
            EmitReaderAccess(sb, col, ordinal);

            if (i < columns.Count - 1)
                sb.Append(',');
            sb.AppendLine();
        }

        sb.AppendLine("        };");
        sb.AppendLine("    }");
        sb.AppendLine();
    }

    private static void EmitReaderAccess(StringBuilder sb, DuckDbColumnInfo col, int ordinal)
    {
        var baseType = col.PropertyType.TrimEnd('?');

        if (col.IsNullable)
        {
            switch (baseType)
            {
                case "string":
                    sb.Append("reader.Col(").Append(ordinal).Append(").AsString");
                    break;
                case "ulong":
                case "System.UInt64":
                    sb.Append("reader.Col(").Append(ordinal).Append(").AsUInt64");
                    break;
                case "long":
                case "System.Int64":
                    sb.Append("reader.Col(").Append(ordinal).Append(").AsInt64");
                    break;
                case "double":
                case "System.Double":
                    sb.Append("reader.Col(").Append(ordinal).Append(").AsDouble");
                    break;
                case "decimal":
                case "System.Decimal":
                    sb.Append("reader.IsDBNull(").Append(ordinal).Append(") ? null : reader.GetDecimal(")
                        .Append(ordinal).Append(')');
                    break;
                case "int":
                case "System.Int32":
                    sb.Append("reader.Col(").Append(ordinal).Append(").AsInt32");
                    break;
                case "byte":
                case "System.Byte":
                    sb.Append("reader.Col(").Append(ordinal).Append(").AsByte");
                    break;
                case "System.DateTimeOffset":
                case "DateTimeOffset":
                    sb.Append("reader.Col(").Append(ordinal).Append(").AsDateTimeOffset");
                    break;
                default:
                    sb.Append("reader.IsDBNull(").Append(ordinal).Append(") ? default : reader.GetValue(")
                        .Append(ordinal).Append(')');
                    break;
            }
        }
        else
        {
            switch (baseType)
            {
                case "string":
                    sb.Append("reader.Col(").Append(ordinal).Append(").GetString(\"\")");
                    break;
                case "ulong":
                case "System.UInt64":
                    sb.Append("reader.Col(").Append(ordinal).Append(").GetUInt64(0UL)");
                    break;
                case "long":
                case "System.Int64":
                    sb.Append("reader.Col(").Append(ordinal).Append(").GetInt64(0L)");
                    break;
                case "double":
                case "System.Double":
                    sb.Append("reader.Col(").Append(ordinal).Append(").GetDouble(0d)");
                    break;
                case "decimal":
                case "System.Decimal":
                    sb.Append("reader.GetDecimal(").Append(ordinal).Append(')');
                    break;
                case "int":
                case "System.Int32":
                    sb.Append("reader.Col(").Append(ordinal).Append(").GetInt32(0)");
                    break;
                case "byte":
                case "System.Byte":
                    sb.Append("reader.Col(").Append(ordinal).Append(").GetByte(0)");
                    break;
                case "System.DateTimeOffset":
                case "DateTimeOffset":
                    sb.Append("reader.Col(").Append(ordinal)
                        .Append(").AsDateTimeOffset ?? default");
                    break;
                default:
                    sb.Append("reader.IsDBNull(").Append(ordinal).Append(") ? default : reader.GetValue(")
                        .Append(ordinal).Append(')');
                    break;
            }
        }
    }

    private static void EmitBuildMultiRowInsertSql(StringBuilder sb, DuckDbTableInfo table)
    {
        sb.AppendLine("    /// <summary>");
        sb.AppendLine("    /// Builds a multi-row INSERT statement with positional parameters.");
        sb.AppendLine("    /// Example: INSERT INTO table (col1, col2) VALUES ($1, $2), ($3, $4)");
        sb.AppendLine("    /// </summary>");
        sb.AppendLine("    public static string BuildMultiRowInsertSql(int rowCount)");
        sb.AppendLine("    {");
        sb.AppendLine("        return s_insertSqlCache.GetOrAdd(rowCount, static count =>");
        sb.AppendLine("        {");
        sb.AppendLine("            var sb = new StringBuilder(1024);");
        sb.Append(
            "            sb.Append(\"INSERT INTO \").Append(QuotedTableName).Append(\" (\").Append(ColumnList).Append(\") VALUES \");");
        sb.AppendLine();
        sb.AppendLine();
        sb.AppendLine("            for (var i = 0; i < count; i++)");
        sb.AppendLine("            {");
        sb.AppendLine("                if (i > 0) sb.Append(\", \");");
        sb.AppendLine();
        sb.AppendLine("                var baseParam = i * ColumnCount;");
        sb.AppendLine("                sb.Append('(');");
        sb.AppendLine("                for (var col = 0; col < ColumnCount; col++)");
        sb.AppendLine("                {");
        sb.AppendLine("                    if (col > 0) sb.Append(\", \");");
        sb.AppendLine("                    sb.Append('$').Append(baseParam + col + 1);");
        sb.AppendLine("                }");
        sb.AppendLine("                sb.Append(')');");
        sb.AppendLine("            }");
        sb.AppendLine();

        if (!string.IsNullOrEmpty(table.OnConflict))
        {
            var onConflict = table.OnConflict!;
            sb.AppendLine("            // ON CONFLICT clause for upsert behavior");
            sb.Append("            sb.Append(\" \").Append(\"\"\"");
            sb.AppendLine();
            foreach (var line in onConflict.Replace("\r\n", "\n").Split('\n'))
            {
                if (string.IsNullOrWhiteSpace(line))
                    continue;

                sb.Append("                ").AppendLine(line.Trim());
            }
            sb.AppendLine("                \"\"\");");
        }

        sb.AppendLine();
        sb.AppendLine("            return sb.ToString();");
        sb.AppendLine("        });");
        sb.AppendLine("    }");
    }
}
